3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Step = {
15	  op: string;
16	  items?: Item[];
17	};
18	
19	type ScenarioInput = {
20	  customer: Customer;
21	  steps: Step[];
22	};
23	
24	type ScenarioOutput = {
25	  results: unknown[];
26	};
27	
28	const PROCESSING_FEE = 5;
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const LOYALTY_YEARS_THRESHOLD = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
36	const COMPONENT_BLOCK_SIZE = 3;
37	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
38	
39	const BASE_PREMIUMS: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	  moonstone: 25,
46	};
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	
50	const isComponentBlock = (type: string, count: number): boolean =>
51	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
52	
53	const surchargeFor = (
54	  items: Item[],
55	  applies: (item: Item) => boolean,
56	  rate: number
57	): number =>
58	  items.reduce(
59	    (surcharge, item) =>
60	      applies(item) ? surcharge + BASE_PREMIUMS[item.type] * rate : surcharge,
61	    0
62	  );
63	
64	const isCursed = (item: Item): boolean => item.cursed === true;
65	
66	const isHighlyEnchanted = (item: Item): boolean =>
67	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
68	
69	const curseSurchargeFor = (items: Item[]): number =>
70	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
71	
72	const enchantmentSurchargeFor = (items: Item[]): number =>
73	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
74	
75	const policyBaseFor = (items: Item[]): number => {
76	  const countsByType = new Map<string, number>();
77	  for (const item of items) {
78	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
79	  }
80	
81	  let policyBase = curseSurchargeFor(items) + enchantmentSurchargeFor(items);
82	  for (const [type, count] of countsByType) {
83	    policyBase += isComponentBlock(type, count)
84	      ? COMPONENT_BLOCK_BASE_PREMIUM
85	      : count * BASE_PREMIUMS[type];
86	  }
87	  return policyBase;
88	};
89	
90	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
91	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
92	
93	const quotePremium = (
94	  items: Item[],
95	  customer: Customer,
96	  isFollowUp: boolean
97	): number => {
98	  const policyBase = policyBaseFor(items);
99	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
100	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
101	    ? policyBase * LOYALTY_DISCOUNT_RATE
102	    : 0;
103	  const followUpDiscount = isFollowUp
104	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
105	    : 0;
106	  return Math.ceil(
107	    policyBase +
108	      firstInsuranceSurcharge -
109	      loyaltyDiscount -
110	      followUpDiscount +
111	      PROCESSING_FEE
112	  );
113	};
114	
115	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
116	
117	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
118	  const results = input.steps.map((step, index) => ({
119	    premium: quotePremium(step.items ?? [], input.customer, isFollowUpQuote(index)),
120	  }));
121	  return { results };
122	};
